-- Migration: bling_nfe_import_v1_20260414_150500_cr_bling_nfe_import_v1.sql
-- Purpose: incremental Bling NF-e import to raw commercial table

create table if not exists public.bling_nfe_documents (
  id uuid primary key default gen_random_uuid(),
  company text not null check (company in ('CZ', 'CR')),
  bling_nfe_id bigint not null,
  invoice_number text,
  issue_datetime timestamp without time zone,
  operation_datetime timestamp without time zone,
  access_key text,
  series text,
  customer_bling_id text,
  customer_name text,
  customer_tax_id text,
  customer_state text,
  natureza_id text,
  salesperson_bling_id text,
  total_amount numeric(14,2) not null default 0,
  freight_amount numeric(14,2) not null default 0,
  first_cfop text,
  payload jsonb not null default '{}'::jsonb,
  source_system text not null default 'bling',
  external_ref text not null,
  created_at timestamp with time zone not null default now(),
  updated_at timestamp with time zone not null default now(),
  unique (source_system, external_ref)
);

-- Upsert NF-e rows from Bling
on conflict (source_system, external_ref) do update set company = excluded.company, bling_nfe_id = excluded.bling_nfe_id, invoice_number = excluded.invoice_number, issue_datetime = excluded.issue_datetime, operation_datetime = excluded.operation_datetime, access_key = excluded.access_key, series = excluded.series, customer_bling_id = excluded.customer_bling_id, customer_name = excluded.customer_name, customer_tax_id = excluded.customer_tax_id, customer_state = excluded.customer_state, natureza_id = excluded.natureza_id, salesperson_bling_id = excluded.salesperson_bling_id, total_amount = excluded.total_amount, freight_amount = excluded.freight_amount, first_cfop = excluded.first_cfop, payload = excluded.payload, updated_at = now();
